          "id": "gauss-curvature-geodesics",
          "title": "Gaussian curvature and geodesics",
          "anchor": "geodesics",
          "prereqs": [
            "first-second-fundamental"
          ],
          "blurb": "Curvature and geodesic flow govern local shape and shortest paths."
